<template>
  <body>
  <div class="header">
    <h1>{{title}}</h1>
    <h2 style="float: right">editor:{{name}}</h2>
  </div>
  <div class="topnav">
    <el-menu
      :default-active="activeIndex"
      class="el-menu-demo"
      mode="horizontal"
      @select="handleSelect"
      background-color="#545c64"
      text-color="#fff"
      active-text-color="#ffd04b">
      <el-menu-item index="1" @click="head()">首页</el-menu-item>
      <el-submenu index="2">
        <template slot="title" @click="open('学习目录')">学习目录</template>
        <el-menu-item index="2-1" @click="open('选项2-1')">iOS</el-menu-item>
        <el-menu-item index="2-2" @click="open('选项2-2')">Android</el-menu-item>
        <el-menu-item index="2-3" @click="open('选项2-3')">Java/服务器</el-menu-item>
        <el-menu-item index="2-4" @click="open('选项2-4')">Vue</el-menu-item>
        <el-submenu index="2-5">
          <template slot="title" @click="open('选项2-5')">选项2-5</template>
          <el-menu-item index="2-5-1" @click="open('选项2-5-1')">选项2-5-1</el-menu-item>
          <el-menu-item index="2-5-2" @click="open('选项2-5-2')">选项2-5-2</el-menu-item>
          <el-menu-item index="2-5-3" @click="open('选项2-5-3')">选项2-5-3</el-menu-item>
        </el-submenu>
      </el-submenu>
      <el-menu-item index="4" @click="about()" style="float: right">
        <p style="color: red">关注订阅号(x小铺)</p>
      </el-menu-item>
    </el-menu>
  </div>

  <div class="row">
    <div class="leftcolumn">
      <!--不能用循环语句的 就单独拉出来显示吧,换一种思路 如果图片大小都做好了控制就不用那么如下纠结了-->
      <div class="card" v-for="item in article" :key="item">
        <h2 class="cardTitle">{{item.title}}</h2>
        <h5 class="cardTime">{{item.time}}</h5>
        <!--v-for 里 v-if判断逻辑-->
        <div class="fakeimg" v-if="item.title === 'x小铺订阅号准备进一步升级'" style="height: 400px;width: 250px;">
          <img :src="item.imgurl" style="height: 100%;width: 100%;border-radius: 10px;">
        </div>
        <div class="fakeimg" v-if="item.title === 'x小铺底部菜单更新'" style="height: 400px;width: 250px;">
          <img :src="item.imgurl" style="height: 100%;width: 100%;border-radius: 10px;">
        </div>
        <!--v-for 里 v-if判断逻辑-->
        <div class="fakeimg" v-else-if="item.title === '关注公众号：x小铺 - 寻找组织'" style="height:400px;width: 280px">
          <img :src="item.imgurl" style="height: 100%;width: 100%;border-radius: 10px;">
        </div>
        <p style="text-align: right">{{item.type}}</p>
        <p style="text-align: left">{{item.content}}</p>
      </div>
    </div>
    <div class="rightcolumn">
      <div class="card">
        <h2>位置推广招租</h2>
      </div>
      <div class="card">
        <h3>关注我的订阅号</h3>
        <p>x小铺</p>
        <p>
          <img src="https://wvqusrtg.oss-cn-hangzhou.aliyuncs.com/20190719/f7c7fb714d0c472b9c298f09151f740d.jpeg" style="height: 100%;width: 100%;border-radius: 10px;">
        </p>
      </div>
    </div>
  </div>
  <div class="footer">
    <h2 style="text-align: left">放手去做、执着坚持！</h2>
    <p style="text-align: left">人生漫漫，我们应该知道自己要走一条什么样的路，并且无比坚信的走下去，即使失败，即使失望，也要是无比坚信的心情，因为你永远不知道它是会成功还是会失败。
      路程中会遇到很多很多麻烦困难，我们需要承受，更要去解决，俞敏洪说过一句话：坚持下去，不是我们有足够的坚强，而是我们已经无法选择。
      不论顺利也好，坎坷也罢，生活中所有的遭遇我们都要淡然接受，永远做生活的强者，不做生活的逃兵。人生是没有退路的，虽然有的时候不免会走点弯路，但那终究是为了向前迈进。人生......</p>
    <br/>
    <p><b>Copyright &copy; 2019 <a href="https://nixinsheng.github.io/"
                                   target="_blank">https://nixinsheng.github.io/</a> All Rights Reserved</b></p>
  </div>

  </body>
</template>

<script>
export default {
  name: 'index',
  data () {
    return {
      title: '关注我的公众号-寻找组织',
      name: '倪新生',
      activeIndex: '1',
      article: [
        {
          title: 'x小铺订阅号准备进一步升级',
          time: '时间待定',
          imgurl: 'https://wvqusrtg.oss-cn-hangzhou.aliyuncs.com/20190809/login.png',
          type: '订阅号',
          content: 'x小铺订阅号准备进一步升级-(升级方案：20190806jeewx-boot)-时间待定'
        },
        {
          title: 'x小铺底部菜单更新',
          time: '2019年07月18日',
          imgurl: 'https://wvqusrtg.oss-cn-hangzhou.aliyuncs.com/20190719/66e3b0ba7d0b4850b03664a29b3703ac.png',
          type: '订阅号',
          content: 'x小铺的底部菜单又回来了，这次小编把底部菜单的响应和小编部署到github上的静态个人主页关联到了一起！更多更新期待中...'
        },
        {
          title: '关注公众号：x小铺 - 寻找组织',
          time: '2019年07月18日10:24:32',
          imgurl: 'https://wvqusrtg.oss-cn-hangzhou.aliyuncs.com/20190719/f7c7fb714d0c472b9c298f09151f740d.jpeg',
          type: '订阅号',
          content: 'x小铺'
        }
      ]
    }
  },
  methods: {
    handleSelect (key, keyPath) {
      console.log(key, keyPath)
    },
    open (msg) {
      this.$alert('"' + msg + '"开发中...', '温馨提示', {
        confirmButtonText: '确定',
        callback: action => {
          this.$message({
            type: 'info',
            message: `action: ${action}`
          })
        }
      })
    },
    head () {
      this.$router.replace({
        path: '/'
      })
    },
    about () {
      this.$router.replace({
        path: './FocusMe'
      })
    }
  }
}
</script>

<style scoped>
  * {
    box-sizing: border-box;
  }

  body {
    font-family: Arial;
    padding: 10px;
    background: #f1f1f1;
  }

  /* 头部标题 */
  .header {
    padding: 30px;
    text-align: center;
    background: linear-gradient(to top right, #CDDC39 0%, #B1CEF7 45%, #5F9DDC 100%);
    font-family: "Xingkai SC";
  }

  .header h1 {
    font-size: 50px;
  }

  /* 导航条 */
  .topnav {
    overflow: hidden;
    background-color: #333;
  }

  /* 导航条链接 */
  .topnav a {
    float: left;
    display: block;
    color: #f2f2f2;
    text-align: center;
    padding: 14px 16px;
    text-decoration: none;
  }

  /* 链接颜色修改 */
  .topnav a:hover {
    background-color: #ddd;
    color: black;
  }

  /* 创建两列 */
  /* Left column */
  .leftcolumn {
    float: left;
    width: 75%;
  }

  /* 右侧栏 */
  .rightcolumn {
    float: left;
    width: 25%;
    background-color: #f1f1f1;
    padding-left: 20px;
  }

  /* 图像部分 */
  .fakeimg {
    background-color: #DDDDDD;
    width: 100%;
    padding: 20px;
  }

  /* 文章卡片效果 */
  .card {
    border-radius: 10px;
    box-shadow: 0 2px 4px rgba(0, 0, 0, .12), 0 0 6px rgba(0, 0, 0, .04);
    background-color: white;
    padding: 20px;
    margin-top: 20px;
  }

  /* 文章标题 */
  .cardTitle {
    text-align: left;
  }

  /* 文章发布时间 */
  .cardTime {
    text-align: right;
    color: darkgray;
  }

  /* 列后面清除浮动 */
  .row:after {
    content: "";
    display: table;
    clear: both;
  }

  /* 底部 */
  .footer {
    padding: 20px;
    text-align: center;
    background: #ddd;
    margin-top: 20px;
  }

  /* 响应式布局 - 屏幕尺寸小于 800px 时，两列布局改为上下布局 */
  @media screen and (max-width: 800px) {
    .leftcolumn, .rightcolumn {
      width: 100%;
      padding: 0;
    }
  }

  /* 响应式布局 -屏幕尺寸小于 400px 时，导航等布局改为上下布局 */
  @media screen and (max-width: 400px) {
    .topnav a {
      float: none;
      width: 100%;
    }
  }
</style>



